"use client";
import React, { useState, useEffect, useRef } from 'react';
import {
    User, Building2, Truck, DollarSign, FileText, ArrowLeft, Save, Loader2,
    Upload, Trash2, Download, Check, Share2, Lock, AlertTriangle, X, ChevronDown, Plus,
    Facebook, Instagram, MessageCircle, ShoppingBag, ShoppingCart, Globe, Music, LayoutTemplate
} from 'lucide-react';
import CustomDropdown from '@/components/CustomDropdown';
import { useRouter } from 'next/navigation';
import { useSession } from 'next-auth/react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
"use client";
import React, { useState, useEffect, useRef } from 'react';
import {
    User, Building2, Truck, DollarSign, FileText, ArrowLeft, Save, Loader2,
    Upload, Trash2, Download, Check, Share2, Lock, AlertTriangle, X, ChevronDown, Plus,
    Facebook, Instagram, MessageCircle, ShoppingBag, ShoppingCart, Globe, Music, LayoutTemplate
} from 'lucide-react';
import CustomDropdown from '@/components/CustomDropdown';
import { useRouter } from 'next/navigation';
import { useSession } from 'next-auth/react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { toast } from 'sonner';
import {
    useBusinessStore, PROVINCES, SALES_CHANNEL_OPTIONS,
    COURIER_NAMES, COURIER_PRESETS, type CourierRate
} from '@/store/business-store';

// ΓöÇΓöÇΓöÇ Vercel-Style Card Component ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function SettingsCard({ title, description, children, footer, danger = false }: {
    title: string; description?: string; children: React.ReactNode; footer?: React.ReactNode; danger?: boolean;
}) {
    return (
        <div className={`bg-white border rounded-xl shadow-sm ${danger ? 'border-red-200' : 'border-slate-200'}`}>
            <div className="px-5 md:px-6 pt-5 md:pt-6 pb-4 md:pb-5">
                <h3 className={`text-base font-semibold ${danger ? 'text-red-700' : 'text-slate-800'}`}>{title}</h3>
                {description && <p className={`text-sm mt-0.5 ${danger ? 'text-red-500' : 'text-slate-500'}`}>{description}</p>}
                <div className="mt-5">{children}</div>
            </div>
            {footer && (
                <div className="px-5 md:px-6 py-3.5 bg-slate-50 border-t border-slate-200 flex justify-end">
                    {footer}
                </div>
            )}
        </div>
    );
}

// ΓöÇΓöÇΓöÇ Save Button Component ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function SaveButton({ onClick, saving, title = "Save Changes", disabled = false }: { onClick?: () => void; saving: boolean; title?: string; disabled?: boolean }) {
    const isDisabled = saving || disabled;
    return (
        <button onClick={onClick} disabled={isDisabled} type={onClick ? 'button' : 'submit'}
            className={`flex items-center gap-2 px-4 py-2 text-sm font-semibold rounded-lg transition-all duration-200 shadow-sm active:scale-[0.98] ${isDisabled && !saving
                ? 'bg-slate-100 text-slate-400 cursor-not-allowed shadow-none border border-slate-200 active:scale-100'
                : 'text-white bg-emerald-600 hover:bg-emerald-700 disabled:opacity-50 hover:shadow-[0_4px_14px_0_rgba(16,185,129,0.2)]'
                }`}>
            {saving ? <><Loader2 size={14} className="animate-spin" /> Saving...</> : <><Save size={14} /> {title}</>}
        </button>
    );
}

// ΓöÇΓöÇΓöÇ Tab Configuration ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const TABS = [
    { id: 'general', label: 'General', icon: User },
    { id: 'business', label: 'Business Profile', icon: Building2 },
    { id: 'logistics', label: 'Logistics', icon: Truck },
    { id: 'financials', label: 'Financials', icon: DollarSign },
    { id: 'documents', label: 'My Documents', icon: FileText },
];

const INITIAL_DOCS: any[] = [];

// ΓöÇΓöÇΓöÇ Form Schemas ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const passwordSchema = z.object({
    currentPassword: z.string().min(1, 'Current password is required'),
    newPassword: z.string().min(8, 'Password must be at least 8 characters'),
    confirmPassword: z.string().min(8, 'Please confirm your password'),
}).refine(data => data.newPassword === data.confirmPassword, {
    message: "Passwords do not match",
    path: ["confirmPassword"],
});

type PasswordForm = z.infer<typeof passwordSchema>;

// ΓöÇΓöÇΓöÇ Main SettingsClient ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// ΓöÇΓöÇ Tab 1: General ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const GeneralTab = () => {
        const store = useBusinessStore();
        const { data: session } = useSession();
        const router = useRouter();
        const [saving, setSaving] = useState(false);
        const { register, handleSubmit, reset, formState: { isDirty } } = useForm({
            defaultValues: { name: store.account.name, email: session?.user?.email || store.account.email },
        });
        useEffect(() => { reset({ name: store.account.name, email: session?.user?.email || store.account.email }); }, [store.account, session]);

        const onSave = handleSubmit(async (data) => {
            setSaving(true);
            store.setAccount(data);
            await new Promise(r => setTimeout(r, 600));
            setSaving(false);
            toast.success('Account updated successfully');
        });

        // Password Form
        const [pwdSaving, setPwdSaving] = useState(false);
        const [showPwdForm, setShowPwdForm] = useState(false);
        const { register: registerPwd, handleSubmit: handlePwdSubmit, formState: { errors: pwdErrors }, reset: resetPwd } = useForm<PasswordForm>({
            resolver: zodResolver(passwordSchema)
        });

        const onPwdSubmit = async (data: PasswordForm) => {
            setPwdSaving(true);
            await new Promise(r => setTimeout(r, 1000)); // Simulate API change password
            setPwdSaving(false);
            toast.success('Password updated successfully!');
            resetPwd();
            setShowPwdForm(false);
        };

        return (
            <div className="space-y-6 animate-in fade-in duration-300">
                <SettingsCard title="Personal Information" description="Your profile details."
                    footer={<SaveButton onClick={onSave} saving={saving} disabled={!isDirty} />}>
                    <div className="space-y-4 max-w-md">
                        {/* Avatar */}
                        <div className="flex items-center gap-4">
                            <label className="group relative cursor-pointer w-16 h-16 rounded-full bg-slate-100 border-2 border-dashed border-slate-200 flex items-center justify-center overflow-hidden hover:border-emerald-400 transition-all duration-300">
                                <input type="file" accept="image/*" className="hidden" onChange={e => {
                                    const file = e.target.files?.[0];
                                    if (file) { const r = new FileReader(); r.onloadend = () => store.setAccount({ avatar: r.result as string }); r.readAsDataURL(file); }
                                }} />
                                {store.account.avatar
                                    ? <img src={store.account.avatar} alt="Avatar" className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-300" />
                                    : <User size={24} className="text-slate-400 group-hover:scale-110 transition-transform duration-300 group-hover:text-emerald-500" />
                                }
                            </label>
                            <div>
                                <p className="text-sm font-medium text-slate-700">Profile Photo</p>
                                <p className="text-xs text-slate-400">Click to upload. JPG, PNG.</p>
                            </div>
                        </div>
                        <div className="space-y-1.5">
                            <label className="text-xs font-semibold text-slate-600">Full Name</label>
                            <input {...register('name')} placeholder="Ali Khan" className="w-full px-3.5 py-2.5 border border-slate-200 rounded-lg text-sm outline-none focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-shadow" />
                        </div>
                        <div className="space-y-1.5">
                            <label className="text-xs font-semibold text-slate-600">Email Address</label>
                            <input {...register('email')} type="email" placeholder="you@example.com" className="w-full px-3.5 py-2.5 border border-slate-200 rounded-lg text-sm outline-none focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-shadow bg-slate-100 text-slate-500 cursor-not-allowed" readOnly disabled />
                            <p className="text-[10px] text-slate-400">Email cannot be changed.</p>
                        </div>
                    </div>
                </SettingsCard>

                <SettingsCard title="Security" description="Manage authentication and account safety.">
                    {!showPwdForm ? (
                        <button onClick={() => setShowPwdForm(true)} className="flex items-center gap-2 px-4 py-2.5 bg-white text-slate-700 border border-slate-200 rounded-lg text-sm font-medium hover:bg-slate-50 transition-all duration-200 active:scale-[0.98]">
                            <Lock size={14} /> Change Password
                        </button>
                    ) : (
                        <form onSubmit={handlePwdSubmit(onPwdSubmit)} className="space-y-4 max-w-sm mt-2">
                            <div className="space-y-1.5">
                                <label className="text-xs font-semibold text-slate-600">Current Password</label>
                                <input type="password" {...registerPwd('currentPassword')} className="w-full px-3.5 py-2.5 border border-slate-200 rounded-lg text-sm outline-none focus:ring-2 focus:ring-emerald-500 transition-shadow" />
                                {pwdErrors.currentPassword && <p className="text-[10px] text-red-500">{pwdErrors.currentPassword.message}</p>}
                            </div>
                            <div className="space-y-1.5">
                                <label className="text-xs font-semibold text-slate-600">New Password</label>
                                <input type="password" {...registerPwd('newPassword')} className="w-full px-3.5 py-2.5 border border-slate-200 rounded-lg text-sm outline-none focus:ring-2 focus:ring-emerald-500 transition-shadow" />
                                {pwdErrors.newPassword && <p className="text-[10px] text-red-500">{pwdErrors.newPassword.message}</p>}
                            </div>
                            <div className="space-y-1.5">
                                <label className="text-xs font-semibold text-slate-600">Confirm Password</label>
                                <input type="password" {...registerPwd('confirmPassword')} className="w-full px-3.5 py-2.5 border border-slate-200 rounded-lg text-sm outline-none focus:ring-2 focus:ring-emerald-500 transition-shadow" />
                                {pwdErrors.confirmPassword && <p className="text-[10px] text-red-500">{pwdErrors.confirmPassword.message}</p>}
                            </div>
                            <div className="flex items-center gap-2 pt-2">
                                <SaveButton saving={pwdSaving} title="Update Password" />
                                <button type="button" onClick={() => { setShowPwdForm(false); resetPwd(); }} className="px-4 py-2 text-sm font-medium text-slate-600 hover:text-slate-900 transition-colors">Cancel</button>
                            </div>
                        </form>
                    )}
                </SettingsCard>

                <SettingsCard title="Danger Zone" description="Permanently delete your account and all data." danger>
                    <button className="flex items-center gap-2 px-4 py-2.5 bg-red-50 text-red-700 border border-red-200 rounded-lg text-sm font-medium hover:bg-red-100 transition-all duration-200 active:scale-[0.98]">
                        <AlertTriangle size={14} className="animate-pulse" /> Delete Account
                    </button>
                </SettingsCard>
            </div>
        );
    };

    // ΓöÇΓöÇ Tab 2: Business Profile ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const BusinessTab = () => {
        const store = useBusinessStore();
        const { data: session } = useSession();
        const router = useRouter();
        const [saving, setSaving] = useState(false);
        const { register, handleSubmit, reset, watch, setValue, formState: { isDirty } } = useForm({
            defaultValues: {
                businessName: store.businessInfo.businessName,
                phone: store.businessInfo.phone,
                address: store.businessInfo.address,
                city: store.businessInfo.city,
                province: store.businessInfo.province,
            },
        });
        const provinceValue = watch('province');
        useEffect(() => { reset({ businessName: store.businessInfo.businessName, phone: store.businessInfo.phone, address: store.businessInfo.address, city: store.businessInfo.city, province: store.businessInfo.province }); }, [store.businessInfo]);

        const [channels, setChannels] = useState(store.salesChannels);
        const [channelsSaving, setChannelsSaving] = useState(false);

        const onSaveBiz = handleSubmit(async (data) => {
            setSaving(true);
            store.setBusinessInfo(data);
            await store.saveProfile();
            await new Promise(r => setTimeout(r, 600));
            setSaving(false);
            toast.success('Business identity saved');
        });

        const onSaveChannels = async () => {
            setChannelsSaving(true);
            store.setSalesChannels(channels);
            await store.saveProfile();
            await new Promise(r => setTimeout(r, 600));
            setChannelsSaving(false);
            toast.success('Sales channels updated');
        };

        const toggleCh = (ch: string) => setChannels(prev => prev.includes(ch) ? prev.filter(c => c !== ch) : [...prev, ch]);

        return (
            <div className="space-y-6 animate-in fade-in duration-300">
                {/* Logo Card */}
                <SettingsCard title="Store Logo" description="Appears on invoices, shipping labels, and packing slips.">
                    <div className="flex items-center gap-5">
                        <label className="cursor-pointer w-20 h-20 rounded-xl bg-slate-50 border-2 border-dashed border-slate-200 flex flex-col items-center justify-center overflow-hidden hover:border-emerald-400 hover:bg-emerald-50 transition-all duration-300 group">
                            <input type="file" accept="image/*" className="hidden" onChange={e => {
                                const file = e.target.files?.[0];
                                if (file) { const r = new FileReader(); r.onloadend = () => { store.setBusinessInfo({ logo: r.result as string }); toast.success('Logo uploaded'); }; r.readAsDataURL(file); }
                            }} />
                            {store.businessInfo.logo
                                ? <img src={store.businessInfo.logo} alt="Logo" className="w-full h-full object-contain p-2 group-hover:scale-105 transition-transform duration-300" />
                                : <div className="flex flex-col items-center transform group-hover:-translate-y-0.5 transition-transform duration-300">
                                    <Upload size={20} className="text-slate-400 group-hover:text-emerald-500 transition-colors mb-0.5" />
                                    <span className="text-[9px] font-semibold text-slate-400 group-hover:text-emerald-500 uppercase">Upload</span>
                                </div>
                            }
                        </label>
                        {store.businessInfo.logo && (
                            <button onClick={() => { store.setBusinessInfo({ logo: null }); toast.success('Logo removed'); }}
                                className="text-xs text-red-500 hover:text-red-700 font-medium flex items-center gap-1"><X size={12} /> Remove</button>
                        )}
                    </div>
                </SettingsCard>

                {/* Business Identity Card */}
                <SettingsCard title="Business Identity" description="Used across all generated documents."
                    footer={<SaveButton onClick={onSaveBiz} saving={saving} disabled={!isDirty} />}>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-w-2xl">
                        <div className="space-y-1.5">
                            <label className="text-xs font-semibold text-slate-600">Business Name</label>
                            <input {...register('businessName')} className="w-full px-3.5 py-2.5 border border-slate-200 rounded-lg text-sm outline-none focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-shadow" />
                        </div>
                        <div className="space-y-1.5">
                            <label className="text-xs font-semibold text-slate-600">Support Phone</label>
                            <input {...register('phone')} placeholder="+92 300 1234567" className="w-full px-3.5 py-2.5 border border-slate-200 rounded-lg text-sm outline-none focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-shadow" />
                        </div>
                        <div className="space-y-1.5">
                            <label className="text-xs font-semibold text-slate-600">City</label>
                            <input {...register('city')} className="w-full px-3.5 py-2.5 border border-slate-200 rounded-lg text-sm outline-none focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-shadow" />
                        </div>
                        <div className="space-y-1.5 z-50 relative">
                            <label className="text-xs font-semibold text-slate-600">Province</label>
                            <CustomDropdown options={PROVINCES} value={provinceValue} onChange={val => setValue('province', val, { shouldDirty: true })} />
                        </div>
                        <div className="md:col-span-2 space-y-1.5">
                            <label className="text-xs font-semibold text-slate-600">Full Street Address</label>
                            <textarea {...register('address')} rows={2} placeholder="House #, Street, Area..." className="w-full px-3.5 py-2.5 border border-slate-200 rounded-lg text-sm outline-none focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-shadow resize-none" />
                        </div>
                    </div>
                </SettingsCard>

                {/* Sales Channels Card */}
                <SettingsCard title="Sales Channels" description="Where you sell your products."
                    footer={<SaveButton onClick={onSaveChannels} saving={channelsSaving} disabled={JSON.stringify(channels) === JSON.stringify(store.salesChannels)} />}>
                    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-3">
                        {SALES_CHANNEL_OPTIONS.map(ch => {
                            const isSelected = channels.includes(ch);

                            let logoUrl = '';
                            if (ch === 'WhatsApp') logoUrl = 'https://upload.wikimedia.org/wikipedia/commons/6/6b/WhatsApp.svg';
                            else if (ch === 'Facebook') logoUrl = 'https://upload.wikimedia.org/wikipedia/commons/b/b8/2021_Facebook_icon.svg';
                            else if (ch === 'Instagram') logoUrl = 'https://upload.wikimedia.org/wikipedia/commons/9/95/Instagram_logo_2022.svg';
                            else if (ch === 'Shopify') logoUrl = 'https://cdn.simpleicons.org/shopify/95BF47';
                            else if (ch === 'TikTok') logoUrl = 'https://cdn.simpleicons.org/tiktok/000000';

                            return (
                                <button key={ch} onClick={() => toggleCh(ch)}
                                    className={`relative flex items-center gap-3 px-3 py-2.5 rounded-xl border transition-all group ${isSelected
                                        ? 'border-emerald-500 bg-emerald-50 shadow-sm'
                                        : 'border-slate-200 bg-white hover:border-slate-300 hover:bg-slate-50'
                                        }`}>
                                    {isSelected && (
                                        <div className="absolute -top-1.5 -right-1.5 bg-emerald-500 text-white p-0.5 rounded-full z-10 shadow-sm animate-in zoom-in duration-200">
                                            <Check size={10} strokeWidth={3} />
                                        </div>
                                    )}


                                    <span className={`text-sm font-semibold truncate ${isSelected ? 'text-emerald-700' : 'text-slate-600'}`}>
                                        {ch}
                                    </span>
                                </button>
                            );
                        })}
                    </div>
                </SettingsCard>
            </div>
        );
    };

    // ΓöÇΓöÇ Tab 3: Logistics & Couriers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const LogisticsTab = () => {
        const store = useBusinessStore();
        const { data: session } = useSession();
        const router = useRouter();

        const [saving, setSaving] = useState(false)
        const [localCouriers, setLocalCouriers] = useState<CourierRate[]>(store.couriers)

        const [showCustomInput, setShowCustomInput] = useState(false)
        const [customName, setCustomName] = useState('')
        const [isDropdownOpen, setIsDropdownOpen] = useState(false)

        const customInputRef = useRef<HTMLInputElement>(null)
        const dropdownRef = useRef<HTMLDivElement>(null)

        useEffect(() => {
            setLocalCouriers(store.couriers)
        }, [store.couriers])

        useEffect(() => {
            if (showCustomInput && customInputRef.current) {
                customInputRef.current.focus()
            }
        }, [showCustomInput])

        // Close dropdown on click outside
        useEffect(() => {
            const handler = (e: MouseEvent) => {
                if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
                    setIsDropdownOpen(false)
                }
            }
            document.addEventListener('mousedown', handler)
            return () => document.removeEventListener('mousedown', handler)
        }, [])


        const addCourier = (name: string) => {

            const clean = name.trim()

            if (!clean) return

            const exists = localCouriers.some(
                c => c.courierName.toLowerCase() === clean.toLowerCase()
            )

            if (exists) {
                toast.error('Courier already exists')
                return
            }

            const preset = COURIER_PRESETS[clean] || {
                sameCity: 0,
                sameProvince: 0,
                crossProvince: 0,
                extraKg: 0
            }

            setLocalCouriers(prev => [
                ...prev,
                { courierName: clean, ...preset }
            ])
        }





        const handleCustomCourierAdd = () => {

            if (!customName.trim()) return

            addCourier(customName)

            setCustomName('')
            setShowCustomInput(false)

        }


        const removeCourier = (i: number) => {
            setLocalCouriers(localCouriers.filter((_, idx) => idx !== i))
        }


        const updateRate = (i: number, field: keyof CourierRate, val: string) => {

            setLocalCouriers(prev =>
                prev.map((c, idx) =>
                    idx === i ? { ...c, [field]: Number(val) } : c
                )
            )

        }


        const onSave = async () => {

            setSaving(true)

            store.setCouriers(localCouriers)

            await store.saveProfile()

            await new Promise(r => setTimeout(r, 500))

            setSaving(false)

            toast.success('Courier rates saved')

        }


        // Exclude 'Other' from COURIER_NAMES (it's appended separately at the end)
        const availableCouriers = COURIER_NAMES.filter(
            c => c !== 'Other' && !localCouriers.some(
                r => r.courierName.toLowerCase() === c.toLowerCase()
            )
        )


        return (

            <div className="animate-in fade-in duration-300">

                <SettingsCard
                    title="Courier Rate Configuration"
                    description="Manage delivery companies and their shipping rates."
                    footer={<SaveButton onClick={onSave} saving={saving} disabled={JSON.stringify(localCouriers) === JSON.stringify(store.couriers)} />}
                >

                    {/* ΓöÇΓöÇ Add Courier ΓöÇΓöÇ */}
                    <div className="flex flex-col sm:flex-row sm:items-start gap-3 mb-8">

                        {/* Custom Dropdown (Order Management filter style) */}
                        <div className="relative" ref={dropdownRef}>
                            <button
                                type="button"
                                onClick={() => setIsDropdownOpen(!isDropdownOpen)}
                                className="w-full sm:w-56 bg-white border border-slate-200 text-slate-700 py-2 sm:py-2.5 px-3 sm:px-4 rounded-xl text-xs sm:text-sm font-bold flex items-center justify-between gap-2 shadow-sm hover:bg-slate-50 transition whitespace-nowrap"
                            >
                                <span className="flex items-center gap-2">
                                    <Plus size={15} className="text-emerald-600" />
                                    Add Courier Company
                                </span>
                                <ChevronDown size={14} className={`text-slate-400 transition-transform duration-200 ${isDropdownOpen ? 'rotate-180' : ''}`} />
                            </button>

                            {isDropdownOpen && (
                                <div className="absolute top-full left-0 mt-1.5 w-full sm:w-56 bg-white border border-slate-200 rounded-xl shadow-[0_8px_30px_rgb(0,0,0,0.12)] z-[999] overflow-hidden">
                                    <div className="max-h-60 overflow-y-auto">
                                        {availableCouriers.map(name => (
                                            <div
                                                key={name}
                                                onClick={() => {
                                                    addCourier(name)
                                                    setIsDropdownOpen(false)
                                                    setShowCustomInput(false)
                                                }}
                                                className="px-4 py-2.5 text-sm font-bold cursor-pointer transition text-slate-600 hover:bg-slate-50"
                                            >
                                                {name}
                                            </div>
                                        ))}
                                    </div>
                                    <div className="border-t border-slate-100" />
                                    <div
                                        onClick={() => {
                                            setShowCustomInput(true)
                                            setIsDropdownOpen(false)
                                        }}
                                        className="px-4 py-2.5 text-sm font-bold cursor-pointer transition text-emerald-600 hover:bg-emerald-50 flex items-center gap-2"
                                    >
                                        <Plus size={14} />
                                        Other (Custom Name)
                                    </div>
                                </div>
                            )}
                        </div>

                        {showCustomInput && (
                            <div className="flex items-center gap-2">
                                <input
                                    ref={customInputRef}
                                    type="text"
                                    placeholder="Enter Courier Company Name"
                                    className="px-3.5 py-2.5 border border-emerald-300 bg-emerald-50/30 rounded-xl text-sm outline-none focus:ring-2 focus:ring-emerald-500 w-full sm:w-56"
                                    value={customName}
                                    onChange={e => setCustomName(e.target.value)}
                                    onKeyDown={(e) => {
                                        if (e.key === 'Enter') handleCustomCourierAdd()
                                        if (e.key === 'Escape') {
                                            setShowCustomInput(false)
                                            setCustomName('')
                                        }
                                    }}
                                />
                                <button
                                    onClick={handleCustomCourierAdd}
                                    className="px-4 py-2.5 bg-emerald-600 text-white rounded-xl text-sm font-semibold hover:bg-emerald-700 transition-colors shadow-sm whitespace-nowrap"
                                >
                                    Add
                                </button>
                                <button
                                    onClick={() => {
                                        setShowCustomInput(false)
                                        setCustomName('')
                                    }}
                                    className="p-2 text-slate-400 hover:text-slate-700 hover:bg-slate-100 rounded-lg transition-colors"
                                >
                                    <X size={16} />
                                </button>
                            </div>
                        )}
                    </div>

                    {/* ΓöÇΓöÇ Courier Rates Table ΓöÇΓöÇ */}
                    {localCouriers.length > 0 ? (
                        <div className="space-y-3">
                            {/* Desktop header row - hidden on mobile */}
                            <div className="hidden md:grid grid-cols-12 gap-3 text-[10px] uppercase font-bold text-slate-400 px-3">
                                <div className="col-span-3">Company</div>
                                <div className="col-span-2 text-center">Same City</div>
                                <div className="col-span-2 text-center">Same Prov</div>
                                <div className="col-span-2 text-center">Cross Prov</div>
                                <div className="col-span-2 text-center">Extra /Kg</div>
                                <div className="col-span-1"></div>
                            </div>

                            {localCouriers.map((c, i) => (
                                <div key={i} className="bg-white rounded-xl border border-slate-200 overflow-hidden">
                                    {/* Desktop: Grid row */}
                                    <div className="hidden md:grid grid-cols-12 gap-3 items-center p-3">
                                        <div className="col-span-3">
                                            <span className="font-semibold text-sm text-slate-700 truncate">{c.courierName}</span>
                                        </div>
                                        {(['sameCity', 'sameProvince', 'crossProvince', 'extraKg'] as const).map(field => (
                                            <div key={field} className="col-span-2 relative">
                                                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs">Rs</span>
                                                <input type="number" min={0} className="w-full pl-8 pr-3 py-2 text-sm border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-emerald-500" value={c[field]} onChange={e => updateRate(i, field, e.target.value)} />
                                            </div>
                                        ))}
                                        <div className="col-span-1 flex justify-center">
                                            <button onClick={() => removeCourier(i)} className="p-2 hover:bg-red-50 text-slate-400 hover:text-red-600 rounded-lg transition-colors"><Trash2 size={16} /></button>
                                        </div>
                                    </div>

                                    {/* Mobile: Stacked card layout */}
                                    <div className="md:hidden p-3">
                                        <div className="flex items-center justify-between mb-3">
                                            <span className="font-bold text-sm text-slate-800">{c.courierName}</span>
                                            <button onClick={() => removeCourier(i)} className="p-1.5 hover:bg-red-50 text-slate-400 hover:text-red-600 rounded-lg transition-colors"><Trash2 size={14} /></button>
                                        </div>
                                        <div className="grid grid-cols-2 gap-2">
                                            {([['sameCity', 'Same City'], ['sameProvince', 'Same Prov'], ['crossProvince', 'Cross Prov'], ['extraKg', 'Extra /Kg']] as const).map(([field, label]) => (
                                                <div key={field} className="space-y-1">
                                                    <label className="text-[9px] uppercase font-bold text-slate-400 tracking-wide">{label}</label>
                                                    <div className="relative">
                                                        <span className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400 text-[10px]">Rs</span>
                                                        <input type="number" min={0} className="w-full pl-6 pr-2 py-1.5 text-xs border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-emerald-500" value={c[field]} onChange={e => updateRate(i, field, e.target.value)} />
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <p className="text-sm text-slate-400 italic py-6 text-center">
                            No couriers added yet.
                        </p>
                    )}

                </SettingsCard>

            </div>

        )
    };

    // ΓöÇΓöÇ Tab 4: Financials & Expenses ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const FinancialsTab = () => {
        const store = useBusinessStore();
        const { data: session } = useSession();
        const router = useRouter();
        const [saving, setSaving] = useState(false);
        const { register, handleSubmit, watch, reset, formState: { isDirty } } = useForm({
            defaultValues: {
                hosting: store.expenses.hosting,
                internet: store.expenses.internet,
                rent: store.expenses.rent,
                salary: store.expenses.salary,
            },
        });
        const [pkgSaving, setPkgSaving] = useState(false);
        const [pkg, setPkg] = useState(store.expenses.packagingCost);

        useEffect(() => {
            reset({ hosting: store.expenses.hosting, internet: store.expenses.internet, rent: store.expenses.rent, salary: store.expenses.salary });
            setPkg(store.expenses.packagingCost);
        }, [store.expenses]);

        const watchedValues = watch();
        const total = Number(watchedValues.hosting || 0) + Number(watchedValues.internet || 0) + Number(watchedValues.rent || 0) + Number(watchedValues.salary || 0);

        const onSaveExpenses = handleSubmit(async (data) => {
            setSaving(true);
            store.setExpenses({
                hosting: Number(data.hosting),
                internet: Number(data.internet),
                rent: Number(data.rent),
                salary: Number(data.salary),
            });
            await store.saveProfile();
            await new Promise(r => setTimeout(r, 600));
            setSaving(false);
            toast.success('Fixed expenses updated');
        });

        const onSavePkg = async () => {
            setPkgSaving(true);
            store.setExpenses({ packagingCost: Number(pkg) });
            await store.saveProfile();
            await new Promise(r => setTimeout(r, 600));
            setPkgSaving(false);
            toast.success('Packaging cost updated');
        };

        return (
            <div className="space-y-6 animate-in fade-in duration-300">
                <SettingsCard title="Fixed Monthly Expenses" description="These costs are distributed across your profit calculations."
                    footer={<SaveButton onClick={onSaveExpenses} saving={saving} disabled={!isDirty} />}>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 max-w-lg">
                        {[
                            { label: 'Hosting', key: 'hosting' as const },
                            { label: 'Internet', key: 'internet' as const },
                            { label: 'Rent / Ads', key: 'rent' as const },
                            { label: 'Salaries', key: 'salary' as const },
                        ].map(item => (
                            <div key={item.key} className="space-y-1.5">
                                <label className="text-xs font-semibold text-slate-600">{item.label}</label>
                                <input type="number" {...register(item.key, { valueAsNumber: true })}
                                    className="w-full px-3.5 py-2.5 border border-slate-200 rounded-lg text-sm font-semibold outline-none focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-shadow" />
                            </div>
                        ))}
                    </div>
                    <div className="mt-5 pt-4 border-t border-slate-200 flex items-center justify-between max-w-lg">
                        <span className="text-sm font-semibold text-slate-500">Total Fixed Monthly</span>
                        <span className="text-sm font-bold bg-emerald-50 text-emerald-700 px-3 py-1 rounded-md">Rs {total.toLocaleString()}</span>
                    </div>
                </SettingsCard>

                <SettingsCard title="Packaging Cost" description="Per-order packaging expense (box, tape, bubble wrap)."
                    footer={<SaveButton onClick={onSavePkg} saving={pkgSaving} disabled={pkg === store.expenses.packagingCost} />}>
                    <div className="max-w-xs space-y-1.5">
                        <label className="text-xs font-semibold text-slate-600">Cost per Order (Rs)</label>
                        <input type="number" value={pkg} onChange={e => setPkg(Number(e.target.value))}
                            className="w-full px-3.5 py-2.5 border border-slate-200 rounded-lg text-sm font-semibold outline-none focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-shadow" />
                    </div>
                </SettingsCard>
            </div>
        );
    };

    // ΓöÇΓöÇ Tab 5: Documents ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const DocumentsTab = () => {
        const store = useBusinessStore();
        const { data: session } = useSession();
        const router = useRouter();
        const [docs, setDocs] = useState<any[]>([]);
        const [loading, setLoading] = useState(true);

        const fetchDocs = async () => {
            try {
                const res = await fetch('http://127.0.0.1:8000/api/documents');
                if (res.ok) {
                    const data = await res.json();
                    setDocs(data.documents || []);
                }
            } catch (err) {
                console.error('Failed to load documents', err);
            } finally {
                setLoading(false);
            }
        };

        useEffect(() => {
            fetchDocs();
        }, []);

        const handleDelete = async (id: string, ref: string) => {
            try {
                await fetch(`http://127.0.0.1:8000/api/documents/${id}`, { method: 'DELETE' });
                setDocs(docs.filter(d => d.id !== id));
                toast.success(`Deleted ${ref}`);
            } catch (err) {
                toast.error(`Failed to delete ${ref}`);
            }
        };

        const handleDownload = async (id: string, ref: string, format: string) => {
            toast.loading(`Downloading ${ref}...`, { id: 'downloading' });
            try {
                const res = await fetch(`http://127.0.0.1:8000/api/documents/${id}`);
                if (!res.ok) throw new Error("Failed to fetch document");
                const data = await res.json();

                if (data.document && data.document.fileData) {
                    const link = document.createElement('a');
                    link.download = `${ref}.${format || 'png'}`;
                    link.href = data.document.fileData;
                    link.click();
                    toast.success('Downloaded!', { id: 'downloading' });
                } else {
                    toast.error('File data not found', { id: 'downloading' });
                }
            } catch (err) {
                console.error(err);
                toast.error('Failed to download', { id: 'downloading' });
            }
        };

        return (
            <div className="animate-in fade-in duration-300">
                <SettingsCard title="Document History" description="All invoices, labels, and slips you've generated.">
                    {loading ? (
                        <div className="py-12 flex flex-col items-center justify-center text-center">
                            <Loader2 className="animate-spin text-emerald-500 mb-2" size={24} />
                            <p className="text-sm text-slate-500">Loading documents...</p>
                        </div>
                    ) : docs.length === 0 ? (
                        <div className="py-12 bg-slate-50 border border-dashed border-slate-200 rounded-xl flex flex-col items-center justify-center text-center">
                            <FileText size={32} className="text-slate-300 mb-3" />
                            <h4 className="text-sm font-semibold text-slate-700">No generated documents found</h4>
                            <p className="text-xs text-slate-400 mt-1 max-w-xs">Documents you generate will appear here in the history log.</p>
                        </div>
                    ) : (
                        <div>
                            {/* Desktop: Table */}
                            <table className="hidden md:table w-full text-left">
                                <thead>
                                    <tr className="border-b border-slate-200">
                                        <th className="text-xs font-semibold text-slate-500 py-3 px-3 whitespace-nowrap">Type</th>
                                        <th className="text-xs font-semibold text-slate-500 py-3 px-3 whitespace-nowrap">Reference</th>
                                        <th className="text-xs font-semibold text-slate-500 py-3 px-3 whitespace-nowrap">Date</th>
                                        <th className="text-xs font-semibold text-slate-500 py-3 px-3 text-right whitespace-nowrap">Actions</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {docs.map((doc) => (
                                        <tr key={doc.id} className="border-b border-slate-100 hover:bg-slate-50/50 transition-colors group">
                                            <td className="py-3 px-3 whitespace-nowrap">
                                                <span className="text-sm font-medium text-slate-700 flex items-center gap-2">
                                                    <span className="text-base">{doc.type === 'Invoice' ? '≡ƒôä' : doc.type === 'Shipping Label' ? '≡ƒôª' : '≡ƒôï'}</span> {doc.type}
                                                </span>
                                            </td>
                                            <td className="py-3 px-3 whitespace-nowrap">
                                                <code className="text-xs font-mono font-semibold text-slate-600 bg-slate-100 px-2 py-1 rounded">{doc.ref}</code>
                                            </td>
                                            <td className="py-3 px-3 text-sm text-slate-500 whitespace-nowrap">
                                                {new Date(doc.date).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' })}
                                            </td>
                                            <td className="py-3 px-3 text-right whitespace-nowrap">
                                                <div className="flex items-center justify-end gap-1 opacity-70 group-hover:opacity-100 transition-opacity">
                                                </div>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>

                            {/* Mobile: Stacked cards */}
                            <div className="md:hidden space-y-3 mt-4">
                                {docs.map((doc) => (
                                    <div key={doc.id} className="bg-white border border-slate-100 p-3.5 rounded-xl shadow-sm space-y-3">
                                        <div className="flex items-center justify-between">
                                            <span className="text-sm font-semibold text-slate-800 flex items-center gap-2">
                                                <span className="text-lg">{doc.type === 'Invoice' ? '≡ƒôä' : doc.type === 'Shipping Label' ? '≡ƒôª' : '≡ƒôï'}</span> {doc.type}
                                            </span>
                                            <code className="text-[10px] font-mono font-bold text-slate-500 bg-slate-100 px-2 py-1 rounded">{doc.ref}</code>
                                        </div>
                                        <div className="flex items-center justify-between border-t border-slate-50 pt-3">
                                            <div className="space-y-0.5">
                                                <p className="text-[10px] text-slate-400 font-medium uppercase tracking-wider">Generated On</p>
                                                <p className="text-xs text-slate-600 font-semibold">
                                                    {new Date(doc.date).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' })}
                                                </p>
                                            </div>
                                            <div className="flex items-center gap-1.5 shrink-0">
                                                <button onClick={() => handleDownload(doc.id, doc.ref, doc.format)} className="p-2 hover:bg-emerald-50 text-emerald-600 rounded-lg transition-colors bg-slate-50 border border-slate-100">
                                                    <Download size={14} />
                                                </button>
                                                <button onClick={() => handleDelete(doc.id, doc.ref)} className="p-2 hover:bg-red-50 text-red-500 rounded-lg transition-colors bg-slate-50 border border-slate-100">
                                                    <Trash2 size={14} />
                                                </button>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </SettingsCard>
            </div>
        );
    };

    export default function SettingsClient() {
        const router = useRouter();
        const { data: session } = useSession();
        const store = useBusinessStore();
        const [activeTab, setActiveTab] = useState('general');

        return (
            <div className="min-h-screen bg-[#f8fafc] font-sans text-slate-800">
                {/* Top Bar */}
                <div className="bg-white border-b border-slate-200 sticky top-0 z-10">
                    <div className="max-w-6xl mx-auto px-4 md:px-8 h-16 flex items-center gap-3">
                        <button onClick={() => router.push('/tools/profit-calculator')} className="p-2 rounded-md hover:bg-slate-100 text-slate-500 transition-colors">
                            <ArrowLeft size={18} />
                        </button>
                        <div>
                            <h1 className="text-lg font-bold text-slate-800 leading-tight">Profile & Settings</h1>
                        </div>
                    </div>
                </div>

                {/* Layout: Scrollable horizontal tabs on mobile, vertical on desktop */}
                <div className="max-w-6xl mx-auto px-4 md:px-8 py-6 md:py-8">
                    <div className="flex flex-col md:flex-row gap-6 md:gap-8">

                        {/* Navigation */}
                        <nav className="md:w-56 flex-shrink-0 -mx-4 px-4 md:mx-0 md:px-0">
                            <div className="md:sticky md:top-24 flex flex-wrap md:flex-col gap-1 md:gap-1.5 pb-2 md:pb-0">
                                {TABS.map(tab => {
                                    const Icon = tab.icon;
                                    const isActive = activeTab === tab.id;
                                    return (
                                        <button key={tab.id} onClick={() => setActiveTab(tab.id)}
                                            className={`flex items-center gap-1.5 md:gap-2.5 px-2.5 md:px-4 py-2 md:py-2.5 rounded-lg md:rounded-xl text-[11px] md:text-sm font-semibold whitespace-nowrap transition-colors
                                                ${isActive ? 'bg-emerald-50 text-emerald-700' : 'text-slate-500 hover:text-slate-800 hover:bg-slate-100'}`}>
                                            <Icon size={14} className={`md:w-4 md:h-4 ${isActive ? 'text-emerald-500' : 'text-slate-400'}`} /> {tab.label}
                                        </button>
                                    );
                                })}
                        </nav>



                    {/* Content Area */}
                    <div className="flex-1 min-w-0">
                        {activeTab === 'general' && <GeneralTab />}
                        {activeTab === 'business' && <BusinessTab />}
                        {activeTab === 'logistics' && <LogisticsTab />}
                        {activeTab === 'financials' && <FinancialsTab />}
                        {activeTab === 'documents' && <DocumentsTab />}
                    </div>
                </div>
            </div>
        </div>
    );
}
